%% seven_dof_robot_damping_comparison.m
% Seven-DoF Planar Robot - Damping Comparison (Non-Singular Configuration)
% Condition 2: theta_i(0) = pi/8 for all i (non-singular)
% Compares SVD-based pseudoinverse vs damped pseudoinverse controllers
% Manual implementation (no qpOASES dependency)

clear all; close all; clc;

try
    include_namespace_dq;
catch
    warning('DQ namespace import failed. Continuing anyway...');
end

fprintf('=== 7-DoF Robot Damping Comparison (Non-Singular Config) ===\n\n'); %[output:6fa65522]

%% Create Robot
% DH matrix: 5 rows x n_dof columns
n_dof = 7;
DH_matrix = zeros(5, n_dof);
for i = 1:n_dof
    DH_matrix(1, i) = 0;  % theta
    DH_matrix(2, i) = 0;  % d
    DH_matrix(3, i) = 1;  % a = 1
    DH_matrix(4, i) = 0;  % alpha
    DH_matrix(5, i) = 0;  % revolute
end
robot = DQ_SerialManipulatorDH(DH_matrix, 'standard');
robot.name = '7-DoF Planar Robot';

%% Configuration
% NON-SINGULAR: theta_i(0) = pi/8 for all joints
q_initial = (pi/8) * ones(7, 1);

% Desired translation: t_d = 5*i + 2*j
t_desired = DQ([0, 5, 2, 0]);
t_desired_vec = vec4(t_desired);

%% Controller Parameters
damping_values = [0.001, 0.005, 0.01, 0.05, 0.1, 0.5, 1, 5];
n_damped = length(damping_values);
n_controllers = 1 + n_damped;  % 1 SVD + 8 damped

gain = 10;
dt = 0.001;
t_max = 5;

% Labels for plotting
labels = cell(1, n_controllers);
labels{1} = 'SVD Pseudoinverse';
for i = 1:n_damped
    labels{i+1} = sprintf('\\lambda = %.3f', damping_values(i));
end

%% Storage
max_steps = ceil(t_max / dt) + 1;
error_history = zeros(n_controllers, max_steps);
control_history = zeros(n_controllers, max_steps);
time_history = zeros(1, max_steps);
steps_taken = zeros(1, n_controllers);

%% Run Controllers
for ctrl_idx = 1:n_controllers %[output:group:355df9cf]
    % Get damping value
    if ctrl_idx == 1
        damping = 0;  % SVD pseudoinverse (no damping)
        fprintf('Running: SVD Pseudoinverse (no damping)\n'); %[output:6273ae59]
    else
        damping = damping_values(ctrl_idx - 1);
        fprintf('Running: Damped Pseudoinverse (lambda = %.3f)\n', damping); %[output:292d985a] %[output:9ee395a0] %[output:7ff97c9a] %[output:21c4ae5a] %[output:26e7f1cf] %[output:182860cd] %[output:3a349251] %[output:2d7e8716]
    end
    
    % Initialize
    q = q_initial;
    t = 0;
    step = 1;
    
    % Control loop
    while t < t_max && step <= max_steps
        % Current translation
        x_current = robot.fkm(q);
        t_current = translation(x_current);
        t_current_vec = vec4(t_current);
        
        % Task error
        task_error = t_desired_vec - t_current_vec;
        error_norm = norm(task_error);
        
        % Store time (only once)
        if ctrl_idx == 1
            time_history(step) = t;
        end
        error_history(ctrl_idx, step) = error_norm;
        
        % Get translation Jacobian
        J_pose = robot.pose_jacobian(q);
        J_trans = robot.translation_jacobian(J_pose, x_current);
        
        % Compute control signal manually
        if damping == 0
            % SVD-based pseudoinverse: J^+ = V * S^+ * U'
            [U, S, V] = svd(J_trans, 'econ');
            s = diag(S);
            tol = max(size(J_trans)) * eps(max(s));
            r = sum(s > tol);
            if r > 0
                S_inv = diag([1./s(1:r); zeros(length(s)-r, 1)]);
                J_pinv = V * S_inv * U';
            else
                J_pinv = zeros(size(J_trans'));
            end
        else
            % Damped pseudoinverse: J^* = J' * (J*J' + lambda^2*I)^{-1}
            lambda_sq = damping^2;
            J_pinv = J_trans' / (J_trans * J_trans' + lambda_sq * eye(size(J_trans, 1)));
        end
        
        % Control law: u = K * J^+ * error
        u = gain * J_pinv * task_error;
        control_norm = norm(u);
        control_history(ctrl_idx, step) = control_norm;
        
        % Update joint positions
        q = q + u * dt;
        t = t + dt;
        step = step + 1;
    end
    
    steps_taken(ctrl_idx) = step - 1;
    fprintf('  Final error: %.6f\n', error_history(ctrl_idx, step-1)); %[output:7f9e1857] %[output:3c74312c] %[output:0ba12151] %[output:20dd9c19] %[output:1be28f29] %[output:6ce594d6] %[output:42531960] %[output:07f14093] %[output:721129ea]
end %[output:group:355df9cf]

%% Trim data to actual steps
n_steps = max(steps_taken);
time_history = time_history(1:n_steps);
error_history = error_history(:, 1:n_steps);
control_history = control_history(:, 1:n_steps);

%% Visualization - Subplot with 1 row, 2 columns
figure('Name', 'Damping Comparison - Non-Singular Configuration', ... %[output:409fe0f9]
       'Position', [100, 100, 1400, 500]); %[output:409fe0f9]

colors = lines(n_controllers);

% LEFT SUBPLOT: Task-space error norm
subplot(1, 2, 1); %[output:409fe0f9]
hold on; %[output:409fe0f9]
for i = 1:n_controllers
    semilogy(time_history, error_history(i, :), 'LineWidth', 1.5, ... %[output:409fe0f9]
             'Color', colors(i, :), 'DisplayName', labels{i}); %[output:409fe0f9]
end
hold off; %[output:409fe0f9]
grid on; %[output:409fe0f9]
xlabel('Time (s)'); %[output:409fe0f9]
ylabel('Task-space Error Norm (log scale)'); %[output:409fe0f9]
title('Task-Space Error Norm - Non-Singular Config (\theta_i(0) = \pi/8)'); %[output:409fe0f9]
legend('Location', 'best', 'FontSize', 8); %[output:409fe0f9]
set(gca, 'YScale', 'log'); %[output:409fe0f9]

% RIGHT SUBPLOT: Control signal norm
subplot(1, 2, 2); %[output:409fe0f9]
hold on; %[output:409fe0f9]
for i = 1:n_controllers
    plot(time_history, control_history(i, :), 'LineWidth', 1.5, ... %[output:409fe0f9]
         'Color', colors(i, :), 'DisplayName', labels{i}); %[output:409fe0f9]
end
hold off; %[output:409fe0f9]
grid on; %[output:409fe0f9]
xlabel('Time (s)'); %[output:409fe0f9]
ylabel('Control Signal Norm'); %[output:409fe0f9]
title('Control Signal Norm - Non-Singular Config (\theta_i(0) = \pi/8)'); %[output:409fe0f9]
legend('Location', 'best', 'FontSize', 8); %[output:409fe0f9]

fprintf('\n=== Comparison Complete (Non-Singular Configuration) ===\n'); %[output:9896d025]

